// ChatFace ai-chat workflow (n8n-safe)
// Uses only this.helpers.httpRequest (no global fetch/process/env).

const first = $input.first();
const body = first?.json?.body ?? first?.json ?? {};

if (body.healthcheck) {
  return [{ json: { ok: true, workflow: 'ai-chat', version: 'v3' } }];
}

const turnId = body.turnId;
const systemPrompt = body.systemPrompt ?? '';
const messages = Array.isArray(body.messages) ? body.messages : [];
const mode = body.mode ?? 'chat';
const sentenceCallbackUrl = body.sentenceCallbackUrl;
const heartbeatCallbackUrl = body.heartbeatCallbackUrl;
const doneCallbackUrl = body.doneCallbackUrl;
const errorCallbackUrl = body.errorCallbackUrl;

if (!turnId || !sentenceCallbackUrl || !doneCallbackUrl) {
  throw new Error('Missing required fields: turnId, sentenceCallbackUrl, doneCallbackUrl');
}

const openAiKey = body.openAiKey;
if (!openAiKey) {
  throw new Error('openAiKey is required in request body');
}

const model = body.openAiModel ?? 'gpt-4o-mini';
const isVoice = mode === 'voice_call' || mode === 'video_call';
const maxTokens = isVoice ? 280 : 1024;

const fireCallback = async (url, payload) => {
  if (!url) return;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      timeout: 6000,
    });
  } catch (_err) {
    // Callback errors must not break generation flow.
  }
};

const openAiMessages = [];
if (systemPrompt) {
  openAiMessages.push({ role: 'system', content: systemPrompt });
}
for (const msg of messages) {
  const parts = Array.isArray(msg?.content) ? msg.content : [];
  const text = parts
    .filter((p) => ['text', 'input_text', 'output_text'].includes(p?.type))
    .map((p) => p?.text ?? '')
    .join('');
  if (text.trim()) {
    openAiMessages.push({ role: msg?.role ?? 'user', content: text });
  }
}

const splitIntoSentences = (rawText) => {
  const text = String(rawText ?? '').trim();
  if (!text) return [];

  const PLACEHOLDER = '\uE000';
  const protectedText = text
    .replace(/\.{2,}/g, (m) => PLACEHOLDER.repeat(m.length))
    .replace(/(\d)\.(\d)/g, `$1${PLACEHOLDER}$2`)
    .replace(
      /\b(Dr|Mr|Mrs|Ms|Prof|Sr|Jr|St|vs|etc|Inc|Ltd|Corp|No|Vol|Dept|approx|Jan|Feb|Mar|Apr|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\./gi,
      (m) => m.slice(0, -1) + PLACEHOLDER,
    );

  const out = [];
  const boundaryRegex = /[.!?。！？…](?:[)\]"'”’]+)?(?=\s|$)/g;
  let cursor = 0;
  let match;

  while ((match = boundaryRegex.exec(protectedText)) !== null) {
    const end = match.index + match[0].length;
    const part = protectedText
      .slice(cursor, end)
      .replace(new RegExp(PLACEHOLDER, 'g'), '.')
      .trim();
    if (part.length >= 4 && /[\p{L}\p{N}]/u.test(part)) {
      out.push(part);
    }
    cursor = end;
  }

  const tail = protectedText
    .slice(cursor)
    .replace(new RegExp(PLACEHOLDER, 'g'), '.')
    .trim();
  if (tail.length >= 4 && /[\p{L}\p{N}]/u.test(tail)) {
    out.push(tail);
  }

  if (!out.length && /[\p{L}\p{N}]/u.test(text)) {
    out.push(text);
  }

  return out;
};

await fireCallback(heartbeatCallbackUrl, { turnId, stage: 'started' });

let openAiResult;
try {
  openAiResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${openAiKey}`,
    },
    body: JSON.stringify({
      model,
      messages: openAiMessages,
      max_tokens: maxTokens,
      temperature: isVoice ? 0.75 : 0.7,
      top_p: 0.9,
      stream: false,
    }),
    timeout: 60000,
  });
} catch (err) {
  await fireCallback(errorCallbackUrl, {
    turnId,
    message: err?.message ?? 'OpenAI request failed',
  });
  throw err;
}

const fullText = String(openAiResult?.choices?.[0]?.message?.content ?? '').trim();
const tokensIn = Number(openAiResult?.usage?.prompt_tokens ?? 0);
const tokensOut = Number(openAiResult?.usage?.completion_tokens ?? 0);

const sentences = splitIntoSentences(fullText);
for (let i = 0; i < sentences.length; i += 1) {
  await fireCallback(sentenceCallbackUrl, {
    turnId,
    sentence: sentences[i],
    index: i,
  });

  if (heartbeatCallbackUrl && (i === 0 || i % 2 === 1)) {
    await fireCallback(heartbeatCallbackUrl, {
      turnId,
      stage: 'dispatching',
      index: i,
    });
  }
}

await fireCallback(doneCallbackUrl, {
  turnId,
  fullText,
  tokensIn,
  tokensOut,
});

return [{
  json: {
    turnId,
    sentCount: sentences.length,
    tokensIn,
    tokensOut,
    status: 'done',
  },
}];

// ─── ChatFace v2: ai-turn-analytics workflow ────────────────────────────
// Logs every AI turn's latency data for observability.
// v2: extended `meta_json` with STT, echo, filler, and n8n-LLM fields.
//
// Required n8n credential: MySQL ('ChatFace DB')

const body = $input.first().json.body ?? $input.first().json;
const timings = body.timings ?? {};

const totalMs = timings.totalMs ?? body.latencyMs ?? 0;
const isSlow     = totalMs > 2500;
const isVerySlow = totalMs > 4500;

const meta = {
  // STT
  sttLang: body.sttLang ?? null,
  sttConfidence: body.sttConfidence ?? null,
  sttRejectionReason: body.sttRejectionReason ?? null,
  // Echo / filler
  echoRejected: body.echoRejected ?? null,
  echoScoreTokenOverlap: body.echoScoreTokenOverlap ?? null,
  echoScoreBigram: body.echoScoreBigram ?? null,
  fillerTriggered: Array.isArray(body.fillerTriggered) ? body.fillerTriggered : null,
  // n8n LLM
  n8nLlmFirstSentenceMs: timings.firstSentenceMs ?? null,
  n8nLlmTotalMs: timings.totalMs ?? null,
  n8nLlmRetries: body.n8nCallRetries ?? null,
  n8nCallStatus: body.n8nCallStatus ?? null,
  // TTS
  ttsFirstChunkMs: timings.firstAudioMs ?? null,
  ttsTotalMs: body.ttsTotalMs ?? null,
  ttsCacheHit: body.ttsCacheHit ?? null,
  // Language lock
  lockedLanguage: body.lockedLanguage ?? null
};

return [{
  json: {
    sessionId:       body.sessionId      ?? null,
    userId:          body.userId         ?? null,
    personaId:       body.personaId      ?? null,
    mode:            body.mode           ?? 'chat',
    language:        body.language       ?? null,
    llmIn:           body.llmIn          ?? 0,
    llmOut:          body.llmOut         ?? 0,
    ttsChars:        body.ttsChars       ?? 0,
    latencyMs:       body.latencyMs      ?? 0,
    prepMs:          timings.prepMs      ?? 0,
    llmFirstTokenMs: timings.llmFirstTokenMs ?? 0,
    firstSentenceMs: timings.firstSentenceMs ?? 0,
    moderationMs:    timings.moderationMs ?? 0,
    totalMs,
    viaN8nLlm:       body.viaN8nLlm      ? 1 : 0,
    isSlow:          isSlow              ? 1 : 0,
    isVerySlow:      isVerySlow          ? 1 : 0,
    meta_json:        JSON.stringify(meta),
    createdAt:       body.timestamp      ?? new Date().toISOString()
  }
}];

// ─── ChatFace v2: moderation-check workflow ─────────────────────────────
// Runs fully async (fire-and-forget from Node). Posts a callback only when
// the result is blocked — Node auto-allows if no callback arrives in time.

const body = $input.first().json.body ?? $input.first().json;
const text = body.text ?? '';
const openAiKey = body.openAiKey;

if (!text || !openAiKey) {
  return [{ json: { blocked: false, skipped: true, reason: 'missing_text_or_key' } }];
}

let result = { flagged: false, categories: {}, category_scores: {} };
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/moderations',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${openAiKey}`
    },
    body: JSON.stringify({
      model: body.model ?? 'omni-moderation-latest',
      input: text
    })
  });
  result = response?.results?.[0] ?? result;
} catch (err) {
  return [{ json: { blocked: false, degraded: true, reason: err.message } }];
}

const categories = result.categories || {};
const flaggedCategories = Object.entries(categories)
  .filter(([, isFlagged]) => Boolean(isFlagged))
  .map(([name]) => name);
const blocked = Boolean(result.flagged);
const reason = flaggedCategories.join(', ') || 'content_policy';

if (blocked && body.callbackUrl) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: body.callbackUrl,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      sessionId: body.sessionId ?? null,
      userId: body.userId ?? null,
      turnId: body.turnId ?? null,
      blocked: true,
      reason,
      flaggedCategories
    })
  }).catch(() => {});
}

return [{
  json: {
    blocked,
    reason,
    flaggedCategories,
    categoryScores: result.category_scores || {},
    sessionId: body.sessionId ?? null,
    userId: body.userId ?? null,
    turnId: body.turnId ?? null,
    createdAt: new Date().toISOString()
  }
}];

// ─── ChatFace v2: tts-synthesize workflow ───────────────────────────────
// Calls ElevenLabs with per-request voice settings (persona-driven).
// Same webhook, same response shape. Adds pooled keep-alive to reduce
// handshake time across back-to-back synth calls.

const bodyHealth = $input.first().json.body ?? $input.first().json;
if (bodyHealth.healthcheck) {
  return [{ json: { ok: true, workflow: 'tts-synthesize', version: 'v2' } }];
}

const body = bodyHealth;
const voiceId = body.voice_id ?? body.voiceId;
if (!voiceId) throw new Error('voiceId is required');
if (!body.text) throw new Error('text is required');

const elevenLabsKey = body.elevenLabsKey;
if (!elevenLabsKey) throw new Error('elevenLabsKey is required in request body');

const payload = {
  text: body.text,
  model_id: body.model_id ?? 'eleven_flash_v2_5',
  voice_settings: body.voice_settings ?? {
    stability: 0.72,
    similarity_boost: 0.8,
    style: 0.08,
    use_speaker_boost: true
  },
  optimize_streaming_latency: body.optimize_streaming_latency ?? 4,
  output_format: body.output_format ?? 'mp3_22050_32'
};

if (body.language_code) payload.language_code = body.language_code;
if (body.previous_text) payload.previous_text = body.previous_text;
if (body.next_text) payload.next_text = body.next_text;
if (body.apply_text_normalization) payload.apply_text_normalization = body.apply_text_normalization;
if (Array.isArray(body.pronunciation_dictionary_locators) && body.pronunciation_dictionary_locators.length) {
  payload.pronunciation_dictionary_locators = body.pronunciation_dictionary_locators;
}

const audioBuffer = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.elevenlabs.io/v1/text-to-speech/${voiceId}/stream`,
  headers: {
    'Content-Type': 'application/json',
    'xi-api-key': elevenLabsKey
  },
  body: JSON.stringify(payload),
  encoding: 'arraybuffer',
  returnFullResponse: false,
  timeout: 30000
});

const base64Audio = Buffer.from(audioBuffer).toString('base64');

return [{ json: { base64Audio } }];

// ─── ChatFace v2: persona-config workflow ───────────────────────────────
// Returns managed persona prompts for Node.js contextBuilder. If no override
// is registered in workflow static data, returns the default prompt so the
// builder falls back gracefully.

const input = $input.first().json;
const personaId = input?.params?.personaId || input?.personaId || null;
const staticData = $getWorkflowStaticData('global');
const prompts = staticData.personaPrompts || {};
const defaultPrompt = prompts.default || '';
const systemPrompt = (personaId && prompts[personaId]) ? prompts[personaId] : defaultPrompt;

return [{ json: { personaId, systemPrompt } }];

// ─── ChatFace v2: filler-audio pre-render workflow ──────────────────────
// Triggered by Node on persona create / update. Iterates the manifest
// (persona × language × scenario × variant), calls tts-synthesize, uploads
// to BunnyCDN, and writes rows into filler_audio_cache via Node callback.
// Failure of one item must not poison the batch.
//
// Body from Node:
//   {
//     personaId, voiceId, styleTag,
//     manifest: [{ personaId, language, scenario, variantIndex, text }...],
//     elevenLabsKey,
//     ttsWebhookUrl,
//     bunnyStorageZone, bunnyAccessKey, bunnyCdnHost, bunnyPathPrefix,
//     intakeCallbackUrl  // Node route that persists cache rows
//   }

const body = $input.first().json.body ?? $input.first().json;
if (body.healthcheck) {
  return [{ json: { ok: true, workflow: 'filler-audio', version: 'v3' } }];
}

const {
  personaId,
  voiceId,
  styleTag,
  manifest,
  elevenLabsKey,
  ttsWebhookUrl,
  bunnyStorageZone,
  bunnyAccessKey,
  bunnyCdnHost,
  bunnyPathPrefix,
  intakeCallbackUrl
} = body;

if (!personaId || !voiceId || !Array.isArray(manifest) || !ttsWebhookUrl || !intakeCallbackUrl) {
  throw new Error('filler-audio: required fields missing');
}
if (!bunnyStorageZone || !bunnyAccessKey || !bunnyCdnHost) {
  throw new Error('filler-audio: BunnyCDN credentials missing');
}

const prefix = (bunnyPathPrefix || 'fillers').replace(/^\/+|\/+$/g, '');
const voiceSettings = {
  stability: 0.72,
  similarity_boost: 0.85,
  style: styleTag === 'playful' ? 0.3 : styleTag === 'concerned' ? 0.12 : 0.08,
  use_speaker_boost: true
};

const results = [];
const errors = [];

for (const item of manifest) {
  try {
    // 1) Synthesize via the shared tts-synthesize webhook.
    const synth = await this.helpers.httpRequest({
      method: 'POST',
      url: ttsWebhookUrl,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        voice_id: voiceId,
        text: item.text,
        model_id: 'eleven_flash_v2_5',
        output_format: 'mp3_22050_32',
        optimize_streaming_latency: 4,
        language_code: item.language,
        voice_settings: voiceSettings,
        elevenLabsKey
      }),
      timeout: 30000
    });

    const audioBase64 = synth?.audio || synth?.base64Audio;
    if (!audioBase64) throw new Error('tts returned no audio');

    const audioBuffer = Buffer.from(audioBase64, 'base64');
    const durationMs = Math.max(400, Math.round((audioBuffer.length / 4000) * 1000));

    // 2) Upload to BunnyCDN.
    const objectKey = `${prefix}/${personaId}/${item.language}/${item.scenario}-${item.variantIndex}.mp3`;
    const cdnUrl = `https://${bunnyCdnHost}/${objectKey}`;

    await this.helpers.httpRequest({
      method: 'PUT',
      url: `https://storage.bunnycdn.com/${bunnyStorageZone}/${objectKey}`,
      headers: {
        AccessKey: bunnyAccessKey,
        'Content-Type': 'audio/mpeg'
      },
      body: audioBuffer,
      timeout: 30000
    });

    // 3) Persist one row per clip to Node intake endpoint.
    const rowPayload = {
      personaId: item.personaId || personaId,
      languageCode: item.language,
      scenario: item.scenario,
      variantIndex: item.variantIndex,
      text: item.text,
      cdnUrl,
      durationMs,
      mouthCuesJson: []
    };

    await this.helpers.httpRequest({
      method: 'POST',
      url: intakeCallbackUrl,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(rowPayload),
      timeout: 15000
    });

    results.push(rowPayload);
  } catch (err) {
    errors.push({
      personaId: item.personaId || personaId,
      languageCode: item.language,
      scenario: item.scenario,
      variantIndex: item.variantIndex,
      error: err.message
    });
  }
}

return [{
  json: {
    personaId,
    rendered: results.length,
    failed: errors.length,
    errors
  }
}];

// ChatFace memory-sync workflow (n8n-safe)
// No process/env usage. Configuration comes from request body, with static fallbacks.

const first = $input.first();
const body = first?.json?.body ?? first?.json ?? {};

if (body.healthcheck) {
  return [{ json: { ok: true, workflow: 'memory-sync', version: 'v2' } }];
}

const STATIC_CONFIG = {
  nodeInternalBaseUrl: 'http://localhost:3000',
  openAiKey: '',
  openAiModel: 'gpt-4o-mini',
  threshold: 10,
  maxSessions: 20,
  maxEntriesPerSession: 5,
  memoryType: 'long_term',
  languageCode: 'en',
  dryRun: false,
};

const nodeInternalBaseUrl = String(
  body.nodeInternalBaseUrl ?? STATIC_CONFIG.nodeInternalBaseUrl ?? '',
).trim().replace(/\/+$/, '');

if (!nodeInternalBaseUrl) {
  throw new Error('memory-sync: nodeInternalBaseUrl is required (body.nodeInternalBaseUrl or STATIC_CONFIG.nodeInternalBaseUrl)');
}

const openAiKey = String(body.openAiKey ?? STATIC_CONFIG.openAiKey ?? '').trim();
if (!openAiKey) {
  throw new Error('memory-sync: openAiKey is required (body.openAiKey or STATIC_CONFIG.openAiKey)');
}

const openAiModel = body.openAiModel ?? STATIC_CONFIG.openAiModel;
const threshold = Math.max(1, Number(body.threshold ?? STATIC_CONFIG.threshold));
const maxSessions = Math.max(1, Number(body.maxSessions ?? STATIC_CONFIG.maxSessions));
const maxEntriesPerSession = Math.max(0, Number(body.maxEntriesPerSession ?? STATIC_CONFIG.maxEntriesPerSession));
const defaultMemoryType = body.memoryType ?? STATIC_CONFIG.memoryType;
const defaultLanguageCode = body.languageCode ?? STATIC_CONFIG.languageCode;
const dryRun = Boolean(body.dryRun ?? STATIC_CONFIG.dryRun);

const toText = (value) => {
  if (typeof value === 'string') return value.trim();
  if (value === null || value === undefined) return '';
  try {
    return JSON.stringify(value);
  } catch (_err) {
    return String(value);
  }
};

const extractMessageText = (content) => {
  if (Array.isArray(content)) {
    const text = content
      .map((part) => toText(part?.text || part?.content || ''))
      .filter(Boolean)
      .join(' ')
      .trim();
    return text || '[non-text message]';
  }

  if (content && typeof content === 'object') {
    const text = toText(content.text || '');
    if (text) return text;
    const attachmentCount = Array.isArray(content.attachments) ? content.attachments.length : 0;
    return attachmentCount ? `[${attachmentCount} attachment(s)]` : '[structured message]';
  }

  return toText(content) || '[empty]';
};

const parseJsonLike = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  const direct = raw.trim();

  try {
    return JSON.parse(direct);
  } catch (_err) {}

  const fenced = direct.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced && fenced[1]) {
    try {
      return JSON.parse(fenced[1].trim());
    } catch (_err) {}
  }

  const start = direct.indexOf('{');
  const end = direct.lastIndexOf('}');
  if (start !== -1 && end > start) {
    try {
      return JSON.parse(direct.slice(start, end + 1));
    } catch (_err) {
      return null;
    }
  }

  return null;
};

const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const allowedEntryTypes = new Set(['short_term', 'long_term', 'persona']);

const getPending = async () => this.helpers.httpRequest({
  method: 'GET',
  url: `${nodeInternalBaseUrl}/api/n8n/memory/pending?threshold=${encodeURIComponent(String(threshold))}`,
});

const postNode = async (path, payload) => this.helpers.httpRequest({
  method: 'POST',
  url: `${nodeInternalBaseUrl}${path}`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload),
});

const summarizeOneSession = async (session) => {
  const messages = Array.isArray(session.messages) ? session.messages : [];
  const messageLines = messages
    .map((msg, index) => `${index + 1}. ${msg.role || 'user'}: ${extractMessageText(msg.content)}`)
    .join('\n');

  const previousSummary = typeof session.previousSummary === 'string' && session.previousSummary.trim()
    ? session.previousSummary.trim()
    : 'None';

  const prompt = [
    'You are a memory distillation assistant for multi-turn chat sessions.',
    'Return strictly JSON (no markdown) with this exact shape:',
    '{"summary":"...","entries":[{"type":"long_term","languageCode":"en","valueJson":{"fact":"..."},"salience":0.7}]}',
    '',
    'Rules:',
    '- summary must be concise (max 90 words), factual, and useful for future context.',
    '- entries must contain only durable user facts/preferences/goals worth keeping long-term.',
    '- Do not include transient turn details as entries.',
    '- If no good entries exist, return entries as [].',
    '',
    `Session ID: ${session.sessionId}`,
    `Previous summary: ${previousSummary}`,
    'New messages:',
    messageLines || '[no messages]',
  ].join('\n');

  const completion = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${openAiKey}`,
    },
    body: JSON.stringify({
      model: openAiModel,
      temperature: 0.2,
      max_tokens: 700,
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'You extract conversation memory and always output strict JSON.',
        },
        {
          role: 'user',
          content: prompt,
        },
      ],
    }),
  });

  const raw = completion?.choices?.[0]?.message?.content || '';
  const parsed = parseJsonLike(raw);
  if (!parsed || typeof parsed !== 'object') {
    throw new Error('OpenAI response is not valid JSON object');
  }

  const summary = toText(parsed.summary).trim();
  const rawEntries = Array.isArray(parsed.entries) ? parsed.entries : [];

  const entries = rawEntries
    .slice(0, maxEntriesPerSession)
    .map((entry) => {
      const type = allowedEntryTypes.has(entry?.type) ? entry.type : defaultMemoryType;
      const languageCode = toText(entry?.languageCode || defaultLanguageCode) || defaultLanguageCode;
      const salienceNum = Number(entry?.salience);
      const salience = Number.isFinite(salienceNum) ? clamp(salienceNum, 0, 1) : 0.5;

      let valueJson = entry?.valueJson;
      if (typeof valueJson === 'string' && valueJson.trim()) {
        valueJson = { fact: valueJson.trim() };
      }
      if (!valueJson || typeof valueJson !== 'object') {
        const fallbackFact = toText(entry?.fact || '');
        if (!fallbackFact) {
          return null;
        }
        valueJson = { fact: fallbackFact };
      }

      return {
        type,
        languageCode,
        valueJson,
        salience,
      };
    })
    .filter(Boolean);

  return { summary, entries };
};

const pendingResp = await getPending();
const pendingSessions = Array.isArray(pendingResp?.pending)
  ? pendingResp.pending.slice(0, maxSessions)
  : [];

const stats = {
  fetched: pendingSessions.length,
  processed: 0,
  summarized: 0,
  entriesSaved: 0,
  dryRun,
  errors: [],
};

for (const session of pendingSessions) {
  stats.processed += 1;
  try {
    const { summary, entries } = await summarizeOneSession(session);

    if (summary && !dryRun) {
      await postNode('/api/n8n/memory/summary', {
        sessionId: session.sessionId,
        summary,
        lastMessageId: session.lastMessageId,
      });
    }

    if (!dryRun && session.userId && entries.length) {
      for (const entry of entries) {
        await postNode('/api/n8n/memory/entries', {
          userId: session.userId,
          type: entry.type,
          languageCode: entry.languageCode,
          valueJson: entry.valueJson,
          salience: entry.salience,
        });
        stats.entriesSaved += 1;
      }
    }

    if (summary) {
      stats.summarized += 1;
    }
  } catch (err) {
    stats.errors.push({
      sessionId: session.sessionId,
      message: err?.message ?? 'unknown_error',
    });
  }
}

return [{ json: stats }];
